INSERT INTO public.simulador_plantillasimulacion (id, activo, fecha_creacion, fecha_modificacion, nombre, codigo, tipo, descripcion, maximo_decisiones, tiempo_estimado, nivel_dificultad, rol_base, contexto_base, objetivo_base, resultado_base, instrucciones_ia, version, es_predeterminada, materia_malla_id, usuario_creacion_id) VALUES (1, true, '2026-06-14 15:47:12.995885-05', '2026-06-14 15:47:12.995892-05', 'Simulacion global por materia - 3 rondas', 'global-decision-3rondas-v1', 'GLOBAL', 'Plantilla base para generar simulaciones con analisis, decision e implementacion en cualquier materia.', 3, 30, 'MEDIA', 'Analista en {materia}', 'La organizacion necesita resolver un problema relacionado con {materia}. El estudiante actua como {rol} y debe responder con datos, conceptos de la materia, criterios de decision e indicadores verificables.', 'Aplicar {materia} para analizar el problema, comparar alternativas y definir una implementacion viable con indicadores de control.', 'El estudiante entrega una decision profesional sustentada con datos, riesgos, conceptos de {materia}, indicadores y acciones verificables.', 'Evalua solo contra la rubrica configurada por el docente. No inventes conceptos, indicadores, impactos ni puntos. La nota la calcula SimutaV2.', 1, true, NULL, NULL);
INSERT INTO public.simulador_simulacion (id, activo, fecha_creacion, fecha_modificacion, titulo, estado, fecha_publicacion, materia_malla_id, usuario_creacion_id, contexto, ia_habilitada, parametros, instrucciones_ia, maximo_decisiones, nivel_dificultad, objetivo, profesor_id, resultado_aprendizaje, rol_estudiante, tema, guia_debriefing, nivel_ayuda_ia, retroalimentacion_base, situacion_inicial, tiempo_estimado, tono_retroalimentacion, tipo_simulacion, api_ia, configuracion_bloqueada, configuracion_snapshot, esquema_ia_version, fecha_bloqueo, metadata_generacion, modelo_ia, prompt_version, version_configuracion, perfil_materia_ia_id, plantilla_origen_id) VALUES (144, true, '2026-06-16 20:02:54.515155-05', '2026-06-16 20:02:54.51519-05', 'Crisis de red en DataNet: SLA, latencia y seguridad', 'PUBLICADA', '2026-06-16 20:02:54.513892-05', 36, 1, 'DataNet Soluciones S.A. opera una red corporativa que conecta su matriz y 4 sucursales. En las ultimas semanas los usuarios reportan lentitud y caidas. Estado actual: disponibilidad 97.2% (SLA exige 99.5%), latencia promedio 180 ms a servicios criticos, perdida de paquetes 4%, el enlace WAN principal opera al 88% de uso sostenido, 12 incidentes de seguridad en el ultimo mes y un MTTR de 6 horas. Actuas como Administrador de Redes y debes diagnosticar, decidir e implementar una solucion medible.', true, '{"area": "Tecnologias de la Informacion", "nivel": 2, "rondas": [{"numero": 1, "titulo": "Diagnostico de la red", "situacion": "La gerencia de DataNet te pide un informe en tres etapas. Primero: como Administrador de Redes, identifica el problema principal de la red, sus causas probables y los indicadores que usarias para medirlo (latencia, perdida de paquetes, disponibilidad, saturacion del enlace, incidentes). Justifica con datos.", "espera_estudiante": "Diagnosticar con metricas de red y herramientas de monitoreo."}, {"numero": 2, "titulo": "Decision tecnica", "situacion": "Con el diagnostico hecho, la gerencia pide una decision en 48 horas. Compara alternativas (QoS/VLAN, enlaces redundantes, seguridad, ampliar ancho de banda), elige una solucion concreta y justifica su impacto en latencia, disponibilidad y seguridad.", "espera_estudiante": "Elegir una solucion de red viable y justificar impacto y riesgo."}, {"numero": 3, "titulo": "Plan de implementacion", "situacion": "La solucion elegida debe implementarse sin afectar la operacion. Define fases, ventana de mantenimiento, responsables, redundancia/alta disponibilidad, monitoreo continuo del SLA y acciones correctivas si algo falla.", "espera_estudiante": "Plan ejecutable con redundancia, monitoreo de SLA y mejora continua."}], "empresa": "DataNet Soluciones S.A.", "eventos": [{"id": "pico_trafico", "ronda": 2, "efecto": {"latencia_ms": 15, "saturacion_wan": 10}, "mensaje": "Una campania masiva dispara el trafico: el enlace WAN se satura mas. Tu plan debe soportar la carga.", "condicion": {"valor": 50, "operador": ">", "indicador": "saturacion_wan"}}], "materia": "Redes de Computadoras"}', 'Evalua solo contra la rubrica configurada de redes. No inventes puntos. La nota la calcula SimutaV2 con conceptos, impactos y restricciones (SLA).', 3, 'AVANZADA', 'Aplicar conceptos de redes para diagnosticar la causa de la baja disponibilidad y la alta latencia, elegir una solucion viable y planificar su implementacion con SLA y seguridad.', 1, 'El estudiante entrega una decision tecnica de redes sustentada con metricas (latencia, perdida, disponibilidad, SLA), seguridad y un plan con redundancia y monitoreo.', 'Administrador de Redes de DataNet Soluciones', 'gestion de redes, SLA, rendimiento y seguridad', '', 'MEDIA', '', 'La gerencia de DataNet te pide un informe en tres etapas. Primero: como Administrador de Redes, identifica el problema principal de la red, sus causas probables y los indicadores que usarias para medirlo (latencia, perdida de paquetes, disponibilidad, saturacion del enlace, incidentes). Justifica con datos.', 30, 'Formativo y claro', 'CON_IA_DINAMICA', 'responses', false, '{}', 'rubrica-docente-v1', NULL, '{}', '', 'simuta-rubrica-v1', 1, NULL, NULL);
INSERT INTO public.simulador_simulacion (id, activo, fecha_creacion, fecha_modificacion, titulo, estado, fecha_publicacion, materia_malla_id, usuario_creacion_id, contexto, ia_habilitada, parametros, instrucciones_ia, maximo_decisiones, nivel_dificultad, objetivo, profesor_id, resultado_aprendizaje, rol_estudiante, tema, guia_debriefing, nivel_ayuda_ia, retroalimentacion_base, situacion_inicial, tiempo_estimado, tono_retroalimentacion, tipo_simulacion, api_ia, configuracion_bloqueada, configuracion_snapshot, esquema_ia_version, fecha_bloqueo, metadata_generacion, modelo_ia, prompt_version, version_configuracion, perfil_materia_ia_id, plantilla_origen_id) VALUES (114, true, '2026-06-16 15:49:01.59056-05', '2026-06-16 15:49:01.590565-05', 'Simulacion - Derecho Laboral', 'PUBLICADA', '2026-06-16 15:49:01.590417-05', 4, 1, 'Cumplimiento Legal Abogados S.A.S. necesita resolver un problema de riesgos laborales, contratos y cumplimiento normativo. Estado actual: horas extra no pagadas 240 al mes, 12 liquidaciones mal aplicadas, 3 demandas en curso, riesgo legal alto y multas acumuladas $8.500. El estudiante actua como responsable tecnico de Derecho Laboral y debe proponer una respuesta breve, concreta y medible.', true, '{"nivel": 1, "rondas": [{"numero": 1, "titulo": "Analisis inicial", "situacion": "Cumplimiento Legal Abogados S.A.S. reporta este estado: horas extra no pagadas 240 al mes, 12 liquidaciones mal aplicadas, 3 demandas en curso, riesgo legal alto y multas acumuladas $8.500. Como analista de Derecho Laboral, identifica el problema principal, sus causas probables y los indicadores que usarias para medirlo.", "espera_estudiante": "Diagnosticar con datos, conceptos de la materia e indicadores medibles."}, {"numero": 2, "titulo": "Decision", "situacion": "La gerencia de Cumplimiento Legal Abogados S.A.S. pide una decision en 48 horas. Compara al menos dos alternativas, estima riesgos y elige una opcion concreta que pueda ejecutarse con los recursos actuales.", "es