INSERT INTO public.simulador_simulacion (id, activo, fecha_creacion, fecha_modificacion, titulo, estado, fecha_publicacion, materia_malla_id, usuario_creacion_id, contexto, ia_habilitada, parametros, instrucciones_ia, maximo_decisiones, nivel_dificultad, objetivo, profesor_id, resultado_aprendizaje, rol_estudiante, tema, guia_debriefing, nivel_ayuda_ia, retroalimentacion_base, situacion_inicial, tiempo_estimado, tono_retroalimentacion, tipo_simulacion, api_ia, configuracion_bloqueada, configuracion_snapshot, esquema_ia_version, fecha_bloqueo, metadata_generacion, modelo_ia, prompt_version, version_configuracion, perfil_materia_ia_id, plantilla_origen_id) VALUES (145, true, '2026-06-16 20:08:58.903469-05', '2026-06-16 20:08:58.903491-05', 'Crisis de rendimiento en TiendaYa: SLA, errores 500 y pruebas', 'PUBLICADA', '2026-06-16 20:08:58.90257-05', 48, 8, 'TiendaYa es una plataforma de e-commerce con 30.000 usuarios. En campañas presenta caidas y lentitud. Estado actual: disponibilidad 98.5% (SLA exige 99.9%), tiempo de respuesta promedio 4.2 s, 15 errores HTTP 500 por dia, el 60% del tiempo de cada peticion se gasta en consultas SQL lentas, cobertura de pruebas 18% y deuda tecnica alta. Actuas como Lider Tecnico y debes diagnosticar, decidir e implementar una solucion medible.', true, '{"area": "Software", "rondas": [{"numero": 1, "titulo": "Diagnostico tecnico", "situacion": "La gerencia de TiendaYa pide un informe en tres etapas. Primero: como Lider Tecnico, identifica el problema principal de rendimiento/calidad, sus causas (consultas SQL, errores 500, falta de pruebas) y los indicadores que usarias para medirlo. Justifica con datos.", "espera_estudiante": "Diagnosticar el rendimiento con metricas y herramientas."}, {"numero": 2, "titulo": "Decision tecnica", "situacion": "Con el diagnostico hecho, decide la solucion: optimizar SQL/indices/cache, agregar pruebas y CI/CD, observabilidad. Compara alternativas y elige una concreta justificando su impacto en tiempo de respuesta, errores y disponibilidad.", "espera_estudiante": "Elegir solucion tecnica viable y justificar impacto."}, {"numero": 3, "titulo": "Plan e implementacion", "situacion": "Implementa sin romper produccion: define fases, despliegue con rollback, monitoreo/observabilidad del SLA, reduccion de deuda tecnica y mejora continua.", "espera_estudiante": "Plan con despliegue seguro, monitoreo y mejora continua."}], "empresa": "TiendaYa"}', 'Evalua solo contra la rubrica configurada. No inventes puntos. La nota la calcula SimutaV2.', 3, 'AVANZADA', 'Diagnosticar la causa de la lentitud y los errores, elegir una solucion (SQL, cache, pruebas, CI/CD, observabilidad) y planificar su despliegue seguro con SLA.', 8, 'El estudiante entrega una decision tecnica sustentada con metricas (tiempo de respuesta, errores 500, cobertura, disponibilidad) y un plan con monitoreo y mejora continua.', 'Lider Tecnico de TiendaYa', 'calidad y rendimiento de software, SLA y pruebas', '', 'MEDIA', '', 'La gerencia de TiendaYa pide un informe en tres etapas. Primero: como Lider Tecnico, identifica el problema principal de rendimiento/calidad, sus causas (consultas SQL, errores 500, falta de pruebas) y los indicadores que usarias para medirlo. Justifica con datos.', 30, 'Formativo y claro', 'CON_IA_DINAMICA', 'responses', false, '{}', 'rubrica-docente-v1', NULL, '{}', '', 'simuta-rubrica-v1', 1, NULL, NULL);
