INSERT INTO public.simulador_accionsugeridasimulacion (id, activo, fecha_creacion, fecha_modificacion, texto, descripcion, impacto_base, simulacion_id, usuario_creacion_id, numero_ronda, costo_recursos) VALUES (645, true, '2026-06-16 20:47:52.620104-05', '2026-06-16 20:47:52.620112-05', 'Tomar un credito bancario inmediato sin revisar el flujo de caja', 'Cubre el deficit hoy, pero sube el endeudamiento y el riesgo financiero.', '{"riesgo": 14, "impacto": -5, "viabilidad": -8}', 155, 1, NULL, '{}');
INSERT INTO public.simulador_accionsugeridasimulacion (id, activo, fecha_creacion, fecha_modificacion, texto, descripcion, impacto_base, simulacion_id, usuario_creacion_id, numero_ronda, costo_recursos) VALUES (646, true, '2026-06-16 20:47:52.648498-05', '2026-06-16 20:47:52.648504-05', 'Diagnosticar el problema con datos antes de decidir', 'Levanta indicadores y causas raiz para sustentar la decision.', '{"claridad": 8, "calidad_analisis": 10}', 156, 1, NULL, '{}');
