, \"retencion\"]}", "impacto_si_falta": {}, "regla_evaluacion": {"all": ["riesgo"], "any": ["rotacion", "salario", "costo", "presupuesto", "retencion"]}, "impacto_si_cumple": {"riesgo_rotacion": -8, "costo_contratacion": -120}, "retroalimentacion_si_falta": "Falta: Gestion de costo y riesgo de rotacion.", "retroalimentacion_si_cumple": "Cumple: Gestion de costo y riesgo de rotacion."}, {"peso": "20.00", "nombre": "Justificacion objetiva sin sesgo", "es_critico": false, "descripcion": "Justificacion objetiva sin sesgo aplicado a Gestion y Administracion del Talento Humano.", "numero_ronda": 2, "palabras_clave": "{\"all\": [\"compar\"], \"any\": [\"evidencia\", \"objetivo\", \"criterio\", \"resultado\", \"puntaje\", \"datos\"]}", "impacto_si_falta": {}, "regla_evaluacion": {"all": ["compar"], "any": ["evidencia", "objetivo", "criterio", "resultado", "puntaje", "datos"]}, "impacto_si_cumple": {"clima_equipo": 8}, "retroalimentacion_si_falta": "Falta: Justificacion objetiva sin sesgo.", "retroalimentacion_si_cumple": "Cumple: Justificacion objetiva sin sesgo."}, {"peso": "20.00", "nombre": "Mejora del proceso de seleccion", "es_critico": false, "descripcion": "Mejora del proceso de seleccion aplicado a Gestion y Administracion del Talento Humano.", "numero_ronda": 3, "palabras_clave": "{\"any\": [\"mejora\", \"leccion\", \"documentacion\", \"proceso\", \"correctiva\"]}", "impacto_si_falta": {}, "regla_evaluacion": {"any": ["mejora", "leccion", "documentacion", "proceso", "correctiva"]}, "impacto_si_cumple": {"clima_equipo": 5}, "retroalimentacion_si_falta": "Falta: Mejora del proceso de seleccion.", "retroalimentacion_si_cumple": "Cumple: Mejora del proceso de seleccion."}, {"peso": "30.00", "nombre": "Plan de onboarding", "es_critico": true, "descripcion": "Plan de onboarding aplicado a Gestion y Administracion del Talento Humano.", "numero_ronda": 3, "palabras_clave": "{\"any\": [\"onboarding\", \"induccion\", \"mentor\", \"plan\", \"primeras semanas\", \"objetivos\",