mpetencia_tecnica", "nombre": "Competencia tecnica (Django)", "unidad": "%", "es_critico": true, "valor_maximo": "100.00", "valor_minimo": "0.00", "valor_inicial": "50.00", "direccion_optima": "ALTO"}, {"codigo": "costo_contratacion", "nombre": "Costo de contratacion", "unidad": "USD", "es_critico": false, "valor_maximo": "2000.00", "valor_minimo": "800.00", "valor_inicial": "1350.00", "direccion_optima": "BAJO"}, {"codigo": "clima_equipo", "nombre": "Encaje con el equipo", "unidad": "%", "es_critico": false, "valor_maximo": "100.00", "valor_minimo": "0.00", "valor_inicial": "50.00", "direccion_optima": "ALTO"}, {"codigo": "riesgo_rotacion", "nombre": "Riesgo de rotacion", "unidad": "%", "es_critico": true, "valor_maximo": "100.00", "valor_minimo": "0.00", "valor_inicial": "55.00", "direccion_optima": "BAJO"}, {"codigo": "tiempo_productividad", "nombre": "Tiempo a productividad", "unidad": "sem", "es_critico": false, "valor_maximo": "16.00", "valor_minimo": "1.00", "valor_inicial": "10.00", "direccion_optima": "BAJO"}], "restricciones": [{"operador": ">=", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": "12.00", "valor_limite": "70.00", "codigo_indicador": "ajuste_perfil"}, {"operador": ">=", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": "12.00", "valor_limite": "70.00", "codigo_indicador": "competencia_tecnica"}, {"operador": "<=", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": "10.00", "valor_limite": "40.00", "codigo_indicador": "riesgo_rotacion"}, {"operador": "<=", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": "6.00", "valor_limite": "6.00", "codigo_indicador": "tiempo_productividad"}], "simulacion_id": 147, "prompt_version": "simuta-rubrica-v1", "acciones_sugeridas": [{"texto": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "descripcion": "Evalua evidencia tecnica real y competencias del puesto.", "impacto_base": {"ajuste_perfil": 15, "riesgo_rotacion": -8, "competencia_tecnica": 18, "tiempo_productividad": -2}, "numero_ronda": 1}, {"texto": "Aplicar solo ejercicios teoricos de Python en pizarra", "descripcion": "Mide parte de la base tecnica, pero no valida Django aplicado al puesto.", "impacto_base": {"ajuste_perfil": -2, "competencia_tecnica": 6, "tiempo_productividad": 1}, "numero_ronda": 1}, {"texto": "Hacer solo entrevista informal con preguntas generales", "descripcion": "No genera evidencia tecnica suficiente para comparar candidatos.", "impacto_base": {"ajuste_perfil": -8, "riesgo_rotacion": 8, "competencia_tecnica": -10}, "numero_ronda": 1}, {"texto": "Contratar a Ana Reyes", "descripcion": "Perfil equilibrado: testing fuerte, comunicacion estable y riesgo bajo.", "impacto_base": {"clima_equipo": 10, "ajuste_perfil": 25, "riesgo_rotacion": -20, "competencia_tecnica": 20, "tiempo_productividad": -4}, "numero_ronda": 2}, {"texto": "Contratar a Luis Carrion", "descripcion": "Muy fuerte en DRF y velocidad, pero con deuda en testing/documentacion.", "impacto_base": {"clima_equipo": -4, "ajuste_perfil": 10, "riesgo_rotacion": 8, "costo_contratacion": -50, "competencia_tecnica": 18, "tiempo_productividad": -2}, "numero_ronda": 2}, {"texto": "Contratar a Marta Sanchez", "descripcion": "Muy fuerte en BD/ORM, pero requiere acompanamiento en comunicacion.", "impacto_base": {"clima_equipo": -8, "ajuste_perfil": 8, "riesgo_rotacion": 4, "costo_contratacion": 50, "competencia_tecnica": 14, "tiempo_productividad": -1}, "numero_ronda": 2}, {"texto": "Contratar al candidato de menor salario sin ponderar la prueba tecnica", "descripcion": "Prioriza costo inmediato por encima de evidencia tecnica y ajuste.", "impacto_base": {"ajuste_perfil": -12, "riesgo_rotacion": 18, "costo_contratacion": -50, "competencia_tecnica": -10}, "numero_ronda": 2}, {"texto": "Ejecutar onboarding 30-60-90 con mentor, objetivos, feedback y plan de carrera", "descripcion": "Acelera productividad y reduce riesgo de salida temprana.", "impacto_base": {"clima_equipo": 12, "ajuste_perfil": 8, "riesgo_rotacion": -16, "tiempo_productividad": -4}, "numero_ronda": 3}, {"texto": "Hacer una induccion de un dia y asignar tareas sin seguimiento", "descripcion": "Arranca rapido, pero deja brechas de acompanamiento y medicion.", "impacto_base": {"clima_equipo": -5, "riesgo_rotacion": 8, "tiempo_productividad": 2}, "numero_ronda": 3}, {"texto": "Ofrecer aumento salarial sin mentor ni metas de desempeno", "descripcion": "Ayuda parcialmente a retencion, pero no resuelve productividad ni seguimiento.", "impacto_base": {"riesgo_rotacion": -4, "costo_contratacion": 120, "tiempo_productividad": 1}, "numero_ronda": 3}], "esquema_ia_version": "rubrica-docente-v1", "plantilla_origen_id": null, "perfil_materia_ia_id": null, "version_configuracion": 1}', false, 99, '{"tiempo": 12.0, "presupuesto": 100.0, "capacidad_equipo": 40.0}');
