brica-v1", "acciones_sugeridas": [{"texto": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "descripcion": "Evalua evidencia tecnica real y competencias del puesto.", "impacto_base": {"ajuste_perfil": 15, "riesgo_rotacion": -8, "competencia_tecnica": 18, "tiempo_productividad": -2}, "numero_ronda": 1, "costo_recursos": {"tiempo": 2, "presupuesto": 12, "capacidad_equipo": 8}}, {"texto": "Aplicar solo ejercicios teoricos de Python en pizarra", "descripcion": "Mide parte de la base tecnica, pero no valida Django aplicado al puesto.", "impacto_base": {"ajuste_perfil": -2, "competencia_tecnica": 6, "tiempo_productividad": 1}, "numero_ronda": 1, "costo_recursos": {"tiempo": 1, "presupuesto": 4, "capacidad_equipo": 3}}, {"texto": "Hacer solo entrevista informal con preguntas generales", "descripcion": "No genera evidencia tecnica suficiente para comparar candidatos.", "impacto_base": {"ajuste_perfil": -8, "riesgo_rotacion": 8, "competencia_tecnica": -10}, "numero_ronda": 1, "costo_recursos": {"tiempo": 1, "presupuesto": 2, "capacidad_equipo": 2}}, {"texto": "Contratar a Ana Reyes", "descripcion": "Perfil equilibrado: testing fuerte, comunicacion estable y riesgo bajo.", "impacto_base": {"clima_equipo": 10, "ajuste_perfil": 25, "riesgo_rotacion": -20, "competencia_tecnica": 20, "tiempo_productividad": -4}, "numero_ronda": 2, "costo_recursos": {"tiempo": 1, "presupuesto": 14, "capacidad_equipo": 4}}, {"texto": "Contratar a Luis Carrion", "descripcion": "Muy fuerte en DRF y velocidad, pero con deuda en testing/documentacion.", "impacto_base": {"clima_equipo": -4, "ajuste_perfil": 10, "riesgo_rotacion": 8, "costo_contratacion": -50, "competencia_tecnica": 18, "tiempo_productividad": -2}, "numero_ronda": 2, "costo_recursos": {"tiempo": 1, "presupuesto": 13, "capacidad_equipo": 4}}, {"texto": "Contratar a Marta Sanchez", "descripcion": "Muy fuerte en BD/ORM, pero requiere acompanamiento en comunicacion.", "impacto_base": {"clima_equipo": -8, "ajuste_perfil": 8, "riesgo_rotacion": 4, "costo_contratacion": 50, "competencia_tecnica": 14, "tiempo_productividad": -1}, "numero_ronda": 2, "costo_recursos": {"tiempo": 1, "presupuesto": 15, "capacidad_equipo": 5}}, {"texto": "Contratar al candidato de menor salario sin ponderar la prueba tecnica", "descripcion": "Prioriza costo inmediato por encima de evidencia tecnica y ajuste.", "impacto_base": {"ajuste_perfil": -12, "riesgo_rotacion": 18, "costo_contratacion": -50, "competencia_tecnica": -10}, "numero_ronda": 2, "costo_recursos": {"tiempo": 1, "presupuesto": 10, "capacidad_equipo": 2}}, {"texto": "Ejecutar onboarding 30-60-90 con mentor, objetivos, feedback y plan de carrera", "descripcion": "Acelera productividad y reduce riesgo de salida temprana.", "impacto_base": {"clima_equipo": 12, "ajuste_perfil": 8, "riesgo_rotacion": -16, "tiempo_productividad": -4}, "numero_ronda": 3, "costo_recursos": {"tiempo": 4, "presupuesto": 18, "capacidad_equipo": 10}}, {"texto": "Hacer una induccion de un dia y asignar tareas sin seguimiento", "descripcion": "Arranca rapido, pero deja brechas de acompanamiento y medicion.", "impacto_base": {"clima_equipo": -5, "riesgo_rotacion": 8, "tiempo_productividad": 2}, "numero_ronda": 3, "costo_recursos": {"tiempo": 1, "presupuesto": 4, "capacidad_equipo": 2}}, {"texto": "Ofrecer aumento salarial sin mentor ni metas de desempeno", "descripcion": "Ayuda parcialmente a retencion, pero no resuelve productividad ni seguimiento.", "impacto_base": {"riesgo_rotacion": -4, "costo_contratacion": 120, "tiempo_productividad": 1}, "numero_ronda": 3, "costo_recursos": {"tiempo": 1, "presupuesto": 25, "capacidad_equipo": 1}}], "esquema_ia_version": "rubrica-docente-v1", "plantilla_origen_id": null, "perfil_materia_ia_id": null, "version_configuracion": 1}', false, NULL, '{"tiempo": 11.0, "presupuesto": 87.0, "capacidad_equipo": 36.0}');
