INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (130, true, '2026-06-17 17:57:43.538418-05', '2026-06-17 17:57:43.53844-05', 1, 'TechAndes te pide un informe en tres etapas. Primero: elige como evaluarias a los finalistas. El puesto requiere Django, DRF, ORM, testing y comunicacion con el equipo. Debes definir criterios medibles y una prueba tecnica real para diferenciar a candidatos parecidos. Justifica con datos del puesto.', 'Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias', 'Para poder saber comoe sta preparada y ver si es contratable', 'La decision propone una evaluacion integral con criterios medibles y diferenciadores, pero carece de justificacion basada en datos del puesto. Se recomienda vincular cada elemento de la prueba con requisitos especificos del rol. Impacto real de la jugada: Indicadores propios afectados: Ajuste al perfil del puesto +15.0 (mejora); Riesgo de rotacion -8.0 (mejora); Competencia tecnica (Django) +18.0 (mejora); Tiempo a productividad -2.0 (mejora).', '{"ajuste_perfil": 15, "riesgo_rotacion": -8, "competencia_tecnica": 18, "tiempo_productividad": -2}', '{"clima_equipo": 50.0, "ajuste_perfil": 50.0, "riesgo_rotacion": 55.0, "costo_contratacion": 1350.0, "competencia_tecnica": 50.0, "tiempo_productividad": 10.0}', '{"__eventos__": [], "clima_equipo": 50.0, "ajuste_perfil": 65.0, "riesgo_rotacion": 47.0, "costo_contratacion": 1350.0, "competencia_tecnica": 68.0, "tiempo_productividad": 8.0}', 70.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actual": 65.0}, {"limite": 70.0, "operador": ">=", "indicador": "competencia_tecnica", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": 12.0, "valor_actual": 68.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 47.0}, {"limite": 6.0, "operador": "<=", "indicador": "tiempo_productividad", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": 6.0, "valor_actual": 8.0}]', 99, NULL, 15.00, 85.00, 'TechAndes revisa la propuesta y solicita detallar como cada prueba medira las competencias clave del puesto, especialmente Django, DRF y testing.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": true, "nombre": "Definicion del perfil y criterios medibles", "impacto": {"ajuste_perfil": 15.0, "riesgo_rotacion": -5.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 2360, "descripcion": "Definicion del perfil y criterios medibles aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "puntos_maximos": 35.0, "puntos_obtenidos": 35.0, "retroalimentacion": "La decision incluye criterios medibles como code review, feature Django, ORM, testing y entrevista por competencias, alineados con el perfil del puesto.", "factor_coincidencia": 1.0, "palabras_detectadas": ["competencias"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Identificar diferenciadores reales", "impacto": {"competencia_tecnica": 6.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 2362, "descripcion": "Identificar diferenciadores reales aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "puntos_maximos": 20.0, "puntos_obtenidos": 20.0, "retroalimentacion": "Se mencionan elementos diferenciadores como testing, Django y ORM, que permiten distinguir entre candidatos.", "factor_coincidencia": 1.0, "palabras_detectadas": ["testing", "django"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Justificacion con datos del puesto", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2363, "descripcion": "Justificacion con datos del puesto aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Para poder saber comoe sta preparada y ver si es contratable", "puntos_maximos": 15.0, "puntos_obtenidos": 0.0, "retroalimentacion": "La justificacion no incluye datos concretos del puesto, requisitos del negocio o necesidades especificas de TechAndes.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["porque", "dato", "requisito", "negocio", "necesidad"], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Metodo de evaluacion objetivo", "impacto": {"ajuste_perfil": 5.0, "competencia_tecnica": 12.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 2361, "descripcion": "Metodo de evaluacion objetivo aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "puntos_maximos": 30.0, "puntos_obtenidos": 30.0, "retroalimentacion": "Se propone un metodo objetivo con prueba tecnica, code review, entrevista por competencias y evaluacion de evidencia.", "factor_coincidencia": 1.0, "palabras_detectadas": ["code review", "entrevista", "competencias"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": null, "costo_recursos": {"tiempo": 2.0, "presupuesto": 12.0, "capacidad_equipo": 8.0}, "alertas_recursos": [], "puntaje_sin_tope": 85.0, "puntaje_conceptos": 85.0, "conceptos_cumplidos": ["Definicion del perfil y criterios medibles", "Identificar diferenciadores reales", "Metodo de evaluacion objetivo"], "conceptos_faltantes": ["Justificacion con datos del puesto"], "conceptos_parciales": [], "penalizacion_recursos": 0, "accion_sugerida_detectada": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "conceptos_criticos_faltantes": []}', 'chat.completions', 'rubrica-docente-v1', 'deepseek-chat', 'simuta-rubrica-v1', '{"conceptos": [{"cumple": true, "factor": 1.0, "evidencia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "concepto_id": 2360, "retroalimentacion": "La decision incluye criterios medibles como code review, feature Django, ORM, testing y entrevista por competencias, alineados con el perfil del puesto."}, {"cumple": true, "factor": 1.0, "evidencia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "concepto_id": 2362, "retroalimentacion": "Se mencionan elementos diferenciadores como testing, Django y ORM, que permiten distinguir entre candidatos."}, {"cumple": false, "factor": 0.0, "evidencia": "Para poder saber comoe sta preparada y ver si es contratable", "concepto_id": 2363, "retroalimentacion": "La justificacion no incluye datos concretos del puesto, requisitos del negocio o necesidades especificas de TechAndes."}, {"cumple": true, "factor": 1.0, "evidencia": "Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias", "concepto_id": 2361, "retroalimentacion": "Se propone un metodo objetivo con prueba tecnica, code review, entrevista por competencias y evaluacion de evidencia."}], "finalizar": false, "siguiente_situacion": "TechAndes revisa la propuesta y solicita detallar como cada prueba medira las competencias clave del puesto, especialmente Django, DRF y testing.", "retroalimentacion_general": "La decision propone una evaluacion integral con criterios medibles y diferenciadores, pero carece de justificacion basada en datos del puesto. Se recomienda vincular cada elemento de la prueba con requisitos especificos del rol."}', 1887, 507, '{"tiempo": 2.0, "presupuesto": 12.0, "capacidad_equipo": 8.0}', '{"tiempo": 12.0, "presupuesto": 100.0, "capacidad_equipo": 40.0}', '{"tiempo": 10.0, "presupuesto": 88.0, "capacidad_equipo": 32.0}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (131, true, '2026-06-17 17:58:57.28204-05', '2026-06-17 17:58:57.282074-05', 2, 'TechAndes revisa la propuesta y solicita detallar como cada prueba medira las competencias clave del puesto, especialmente Django, DRF y testing.', 'Contratar a Luis Carrion', 'porque tien sabe rest framewokr
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (132, true, '2026-06-17 17:59:27.441063-05', '2026-06-17 17:59:27.441108-05', 3, 'TechAndes rechaza la propuesta por falta de sustento técnico y solicita una nueva justificación detallada basada en los perfiles y pruebas de los candidatos. ⚡ Uno de los candidatos recibe una contraoferta externa; ahora la decision debe considerar retencion y costo real.', 'Ejecutar onboarding 30-60-90 con mentor, objetivos, feedback y plan de carrera', '', 'La decisión propone un onboarding estructurado con mentor, objetivos y plan de carrera, lo que aborda retención y seguimiento. Sin embargo, no se justifica la selección del candidato ni se documentan mejoras al proceso de selección, que era lo solicitado por TechAndes. Impacto real de la jugada: Indicadores propios afectados: Ajuste al perfil del puesto +8.0 (mejora); Tiempo a productividad -4.0 (mejora); Encaje con el equipo +12.0 (mejora); Riesgo de rotacion -16.0 (mejora); Competencia tecnica (Django) +3.0 (mejora).', '{"clima_equipo": 12, "ajuste_perfil": 8, "riesgo_rotacion": -16, "competencia_tecnica": 3.0, "tiempo_productividad": -4}', '{"__eventos__": ["db:43"], "clima_equipo": 46.0, "ajuste_perfil": 75.0, "riesgo_rotacion": 67.0, "costo_contratacion": 1420.0, "competencia_tecnica": 86.0, "tiempo_productividad": 6.0}', '{"__eventos__": ["db:43"], "clima_equipo": 58.0, "ajuste_perfil": 83.0, "riesgo_rotacion": 51.0, "costo_contratacion": 1420.0, "competencia_tecnica": 89.0, "tiempo_productividad": 2.0}', 50.00, '[{"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 51.0}]', 99, NULL, 10.00, 67.50, 'TechAndes acepta el plan de onboarding pero solicita que se documenten las lecciones aprendidas del proceso de selección y se definan KPIs específicos para evaluar el desempeño durante el periodo de prueba.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Mejora del proceso de seleccion", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2371, "descripcion": "Mejora del proceso de seleccion aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No se menciona mejora del proceso de selección.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se evidencia mejora del proceso de selección. La decisión se enfoca en onboarding, no en documentar lecciones o correctivas del proceso.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["mejora", "leccion", "documentacion", "proceso", "correctiva"], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Plan de onboarding", "impacto": {"ajuste_perfil": 8.0, "tiempo_productividad": -3.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 2368, "descripcion": "Plan de onboarding aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Ejecutar onboarding 30-60-90 con mentor, objetivos, feedback y plan de carrera.", "puntos_maximos": 30.0, "puntos_obtenidos": 30.0, "retroalimentacion": "La decisión incluye un plan de onboarding estructurado con mentor, objetivos y feedback, cumpliendo