INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (83, true, '2026-06-16 21:17:34.581127-05', '2026-06-16 21:17:34.581158-05', 3, 'TechAndes rechaza la propuesta por no abordar la seleccion del candidato ni la evaluacion tecnica, y solicita una nueva ronda con enfoque en criterios y prueba tecnica. ⚡ Uno de los candidatos recibe una contraoferta externa; ahora la decision debe considerar retencion y costo real.', 'Elegir al mas barato sin prueba tecnica para ahorrar tiempo', 'Riesgoso: decides a ciegas, sube el riesgo de rotacion y mala contratacion.', 'La decisión de elegir al más barato sin prueba técnica es riesgosa y no aborda ninguno de los conceptos requeridos. Se ignora la evaluación técnica, la retención y el plan de onboarding, lo que puede aumentar la rotación y el riesgo de mala contratación.', '{"ajuste_perfil": -10, "riesgo_rotacion": 15, "competencia_tecnica": -8, "tiempo_productividad": 2}', '{"__eventos__": ["db:43"], "clima_equipo": 60.0, "ajuste_perfil": 30.0, "riesgo_rotacion": 70.0, "costo_contratacion": 1410.0, "competencia_tecnica": 36.0, "tiempo_productividad": 7.0}', '{"__eventos__": ["db:43"], "clima_equipo": 60.0, "ajuste_perfil": 20.0, "riesgo_rotacion": 85.0, "costo_contratacion": 1410.0, "competencia_tecnica": 28.0, "tiempo_productividad": 9.0}', 0.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actual": 20.0}, {"limite": 70.0, "operador": ">=", "indicador": "competencia_tecnica", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": 12.0, "valor_actual": 28.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 85.0}, {"limite": 6.0, "operador": "<=", "indicador": "tiempo_productividad", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": 6.0, "valor_actual": 9.0}]', 59, NULL, 15.00, 0.00, 'TechAndes rechaza la propuesta por no cumplir con los criterios de selección y solicita una nueva ronda con enfoque en evaluación técnica y retención.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Mejora del proceso de seleccion", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1755, "descripcion": "Mejora del proceso de seleccion en TechAndes.", "evidencia_ia": "No se menciona mejora, lección, documentación, proceso o correctiva.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se aborda la mejora del proceso de selección.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["mejora", "leccion", "documentacion", "proceso", "correctiva"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Plan de onboarding", "impacto": {"tiempo_productividad": 2}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1752, "descripcion": "Plan de onboarding en TechAndes.", "evidencia_ia": "No se menciona onboarding, inducción, mentor, plan, primeras semanas, objetivos o acompañamiento.", "puntos_maximos": 30.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se propone un plan de onboarding.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["onboarding", "induccion", "mentor", "plan", "primeras semanas", "objetivos", "acompanamiento"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Retencion y plan de carrera", "impacto": {"riesgo_rotacion": 5}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1753, "descripcion": "Retencion y plan de carrera en TechAndes.", "evidencia_ia": "No se menciona retención, plan de carrera, crecimiento, feedback, salario, clima o reconocimiento.", "puntos_maximos": 25.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se aborda la retención ni plan de carrera.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["retencion", "plan de carrera", "crecimiento", "feedback", "salario", "clima", "reconocimiento"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Seguimiento del desempeno", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1754, "descripcion": "Seguimiento del desempeno en TechAndes.", "evidencia_ia": "No se menciona seguimiento, KPI, objetivos, evaluación, periodo de prueba o metas.", "puntos_maximos": 25.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se propone seguimiento del desempeño.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["seguimiento", "kpi", "objetivos", "evaluacion", "periodo de prueba", "metas"], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": 70.0, "costo_recursos": {"tiempo": 2.0, "presupuesto": 10.0, "capacidad_equipo": 10.0}, "alertas_recursos": [], "puntaje_sin_tope": 0, "puntaje_conceptos": 0, "conceptos_cumplidos": [], "conceptos_faltantes": ["Mejora del proceso de seleccion", "Plan de onboarding", "Retencion y plan de carrera", "Seguimiento del desempeno"], "conceptos_parciales": [], "penalizacion_recursos": 0, "accion_sugerida_detectada": "Elegir al mas barato sin prueba tecnica para ahorrar tiempo", "conceptos_criticos_faltantes": ["Plan de onboarding", "Retencion y plan de carrera"]}', 'chat.completions', 'rubrica-docente-v1', 'deepseek-chat', 'simuta-rubrica-v1', '{"conceptos": [{"cumple": false, "factor": 0.0, "evidencia": "No se menciona mejora, lección, documentación, proceso o correctiva.", "concepto_id": 1755, "retroalimentacion": "No se aborda la mejora del proceso de selección."}, {"cumple": false, "factor": 0.0, "evidencia": "No se menciona onboarding, inducción, mentor, plan, primeras semanas, objetivos o acompañamiento.", "concepto_id": 1752, "retroalimentacion": "No se propone un plan de onboarding."}, {"cumple": false, "factor": 0.0, "evidencia": "No se menciona retención, plan de carrera, crecimiento, feedback, salario, clima o reconocimiento.", "concepto_id": 1753, "retroalimentacion": "No se aborda la retención ni plan de carrera."}, {"cumple": false, "factor": 0.0, "evidencia": "No se menciona seguimiento, KPI, objetivos, evaluación, periodo de prueba o metas.", "concepto_id": 1754, "retroalimentacion": "No se propone seguimiento del desempeño."}], "finalizar": false, "siguiente_situacion": "TechAndes rechaza la propuesta por no cumplir con los criterios de selección y solicita una nueva ronda con enfoque en evaluación técnica y retención.", "retroalimentacion_general": "La decisión de elegir al más barato sin prueba técnica es riesgosa y no aborda ninguno de los conceptos requeridos. Se ignora la evaluación técnica, la retención y el plan de onboarding, lo que puede aumentar la rotación y el riesgo de mala contratación."}', 1550, 452, '{"tiempo": 2.0, "presupuesto": 10.0, "capacidad_equipo": 10.0}', '{"tiempo": 7.0, "presupuesto": 68.0, "capacidad_equipo": 22.0}', '{"tiempo": 5.0, "presupuesto": 58.0, "capacidad_equipo": 12.0}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (51, true, '2026-06-16 16:12:26.091212-05', '2026-06-16 16:12:26.091232-05', 1, 'Costos Controlados S.A. reporta este estado: costo unitario $45, margen bruto 22%, inventario lento 45 dias rotacion, punto de equilibrio 1.200 unidades y costos fijos $28.000. Como analista de Contabilidad de Costos, identifica el problema principal, sus causas probables y los indicadores que usarias para medirlo.', 'El problema principal es que la empresa tiene costos altos y poca utilidad. El costo unitario es de $45 y el margen bruto solo llega al 22%, por eso la ganancia no es buena. También hay inventario lento porque rota cada 45 días, lo que puede significar que se vende poco o se produce más de lo necesario. Además, el punto de equilibrio de 1.200 unidades es alto frente a los costos fijos de $28.000.', 'Considero que el problema viene de los costos de producción, el manejo del inventario y posiblemente precios o ventas bajas. Para medirlo usaría indicadores como costo unitario, margen bruto, punto de equilibrio, rotación de inventario, costos fijos, ventas y utilidad. Con esos datos se puede saber si la empresa debe reducir costos, mejorar ventas o controlar mejor el inventario.', 'El estudiante identifica el problema y menciona indicadores, pero el análisis es superficial y no profundiza en causas raíz ni aplica herramientas específicas de contabilidad de costos.', '{"riesgo": -3.13, "impacto": 3.48, "claridad": 3.48, "viabilidad": 3.48, "calidad_analisis": 3.48}', '{"riesgo": 50.0, "impacto": 50.0, "claridad": 50.0, "viabilidad": 50.0, "calidad_analisis": 50.0}', '{"riesgo": 46.87, "impacto": 53.48, "claridad": 53.48, "viabilidad": 53.48, "calidad_analisis": 53.48}', 64.50, '[]', 41, NULL, 0.00, 64.50, 'La empresa decide revisar sus costos de producción y rotación de inventario, pero sin un plan concreto, los resultados podrían no mejorar significativamente.', true, 'VALIDO', '{"tipo": "openai_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Analisis del problema", "impacto": {"riesgo": -5.6, "calidad_analisis": 12.6}, "parcial": true, "cumple_ia": true, "es_critico": true, "concepto_id": 1324, "descripcion": "Analisis del problema aplicado a Contabilidad de Costos.", "evidencia_ia": "El problema principal es que la empresa tiene costos altos y poca utilidad.", "puntos_maximos": 35.0, "puntos_obtenidos": 24.5, "retroalimentacion": "Identifica el problema principal, pero no profundiza en causas raíz específicas.", "factor_coincidencia": 0.7, "palabras_detectadas": ["costos", "principal", "problema"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Indicadores y datos", "impacto": {"riesgo": -4.0, "claridad": 8.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 1326, "descripcion": "Indicadores y datos aplicado a Contabilidad de Costos.", "evidencia_ia": "Usaría indicadores como costo unitario, margen bruto, punto de equilibrio, rotación de inventario, costos fijos, ventas y utilidad.", "puntos_maximos": 20.0, "puntos_obtenidos": 16.0, "retroalimentacion": "Menciona indicadores relevantes, aunque algunos son genéricos.", "factor_coincidencia": 0.8, "palabras_detectadas": ["costo", "dato", "indicador", "medir"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Justificacion inicial", "impacto": {"claridad": 4.8}, "parcial": true, "cumple_ia": true, "es_critico": false, "concepto_id": 1327, "descripcion": "Justificacion inicial aplicado a Contabilidad de Costos.", "evidencia_ia": "Considero que el problema viene de los costos de producción, el manejo del inventario y posiblemente precios o ventas bajas.", "puntos_maximos": 15.0, "puntos_obtenidos": 9.0, "retroalimentacion": "Justifica parcialmente, pero no vincula causas con consecuencias de manera sólida.", "factor_coincidencia": 0.6, "palabras_detectadas": ["porque"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Uso de conceptos de la materia", "impacto": {"claridad": 4.0, "calidad_analisis": 6.0}, "parcial": true, "cumple_ia": true, "es_critico": true, "concepto_id": 1325, "descripcion": "Uso de conceptos de la materia aplicado a Contabilidad de Costos.", "evidencia_ia": "El costo unitario es de $45 y el margen bruto solo llega al 22%.", "puntos_maximos": 30.0, "puntos_obtenidos": 15.0, "retroalimentacion": "Usa conceptos de costos, pero no aplica herramientas como análisis de punto de equilibrio o margen de contribución.", "factor_coincidencia": 0.5, "palabras_detectadas": ["costos"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": null, "puntaje_sin_tope": 64.5, "puntaje_conceptos": 64.5, "conceptos_cumplidos": ["Indicadores y datos"], "conceptos_faltantes": [], "conceptos_parciales": ["Analisis del problema", "Justificacion inicial", "Uso de conceptos de la materia"], "conceptos_criticos_faltantes": []}', 'chat.completions', 'rubrica-docente-v1', 'deepseek-chat', 'simuta-rubrica-v1', '{"conceptos": [{"cumple": true, "factor": 0.7, "evidencia": "El problema principal es que la empresa tiene costos altos y poca utilidad.", "concepto_id": 1324, "retroalimentacion": "Identifica el problema principal, pero no profundiza en causas raíz específicas."}, {"cumple": true, "factor": 0.8, "evidencia": "Usaría indicadores como costo unitario, margen bruto, punto de equilibrio, rotación de inventario, costos fijos, ventas y utilidad.", "concepto_id": 1326, "retroalimentacion": "Menciona indicadores relevantes, aunque algunos son genéricos."}, {"cumple": true, "factor": 0.6, "evidencia": "Considero que el problema viene de los costos de producción, el manejo del inventario y posiblemente precios o ventas bajas.", "concepto_id": 1327, "retroalimentacion": "Justifica parcialmente, pero no vincula causas con consecuencias de manera sólida."}, {"cumple": true, "factor": 0.5, "evidencia": "El costo unitario es de $45 y el margen bruto solo llega al 22%.", "concepto_id": 1325, "retroalimentacion": "Usa conceptos de costos, pero no aplica herramientas como análisis de punto de equilibrio o margen de contribución."}], "finalizar": false, "siguiente_situacion": "La empresa decide revisar sus costos de producción y rotación de inventario, pero sin un plan concreto, los resultados podrían no mejorar significativamente.", "retroalimentacion_general": "El estudiante identifica el problema y menciona indicadores, pero el análisis es superficial y no profundiza en causas raíz ni aplica herramientas específicas de contabilidad de costos."}', 0, 0, '{}', '{}', '{}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (52, true, '2026-06-16 16:13:11.374887-05', '2026-06-16 16:13:11.374918-05', 2, 'La empresa decide revisar sus costos de producción y rotación de inventario, pero sin un plan concreto, los resultados podrían no mejorar significativamente.', 'La empresa debe reducir el costo unitario revisando sus costos de producción y comprando mejor la materia prima. También debe controlar el inventario para que no se quede parado 45 días. Propongo revisar proveedores, disminuir desperdicios en producción y producir de acuerdo con la demanda real.', 'Esta decisión ayuda porque el problema principal está en los costos altos y en el inventario lento. Si baja el costo unitario, el margen bruto puede mejorar. Además, si se controla mejor el inventario, la empresa no tendrá tanto dinero detenido en productos que no se venden rápido. Para medir si funciona revisaría el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad mensual.', 'La decisión es concreta y está justificada, pero falta comparar alternativas y gestionar riesgos. Se recomienda incluir un análisis de opciones y medidas de control.', '{}', '{"riesgo": 46.87, "impacto": 53.48, "claridad": 53.48, "viabilidad": 53.48, "calidad_analisis": 53.48}', '{"riesgo": 46.87, "impacto": 53.48, "claridad": 53.48, "viabilidad": 53.48, "calidad_analisis": 53.48}', 50.00, '[]', 41, NULL, 0.00, 50.00, 'La empresa implementa las mejoras en compras y producción, pero sin un plan de riesgos, podrían surgir problemas de calidad o desabastecimiento.', true, 'VALIDO', '{"tipo": "openai_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Alternativas comparadas", "impacto": {"riesgo": 15}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1328, "descripcion": "Alternativas comparadas aplicado a Contabilidad de Costos.", "evidencia_ia": "No se mencionan alternativas comparadas.", "puntos_maximos": 30.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se comparan opciones ni se analizan ventajas/desventajas de distintas alternativas.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["alternativa", "comparar", "desventaja", "opcion", "riesgo", "ventaja", "versus"], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Decision concreta", "impacto": {"impacto": 10.0, "viabilidad": 18.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 1329, "descripcion": "Decision concreta aplicado a Contabilidad de Costos.", "evidencia_ia": "Propongo revisar proveedores, disminuir desperdicios en producción y producir de acuerdo con la demanda real.", "puntos_maximos": 30.0, "puntos_obtenidos": 30.0, "retroalimentacion": "La decisión es concreta y menciona acciones específicas.", "factor_coincidencia": 1.0, "palabras_detectadas": ["costos", "decido", "propongo"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Gestion de riesgos", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1330, "descripcion": "Gestion de riesgos aplicado a Contabilidad de Costos.", "evidencia_ia": "No se mencionan riesgos ni controles.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se identifican riesgos ni se proponen medidas de control o seguimiento.", "factor_coincidencia": 0.0, "palabras_detectadas": ["control"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Justificacion de la decision", "impacto": {"claridad": 12.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 1331, "descripcion": "Justificacion de la decision aplicado a Contabilidad de Costos.", "evidencia_ia": "Esta decisión ayuda porque el problema principal está en los costos altos y en el inventario lento.", "puntos_maximos": 20.0, "puntos_obtenidos": 20.0, "retroalimentacion": "La justificación explica el beneficio esperado y la razón de la decisión.", "factor_coincidencia": 1.0, "palabras_detectadas": ["porque"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": 85.0, "puntaje_sin_tope": 50.0, "puntaje_conceptos": 50.0, "conceptos_cumplidos": ["Decision concreta", "Justificacion de la decision"], "conceptos_faltantes": ["Alternativas comparadas", "Gestion de riesgos"], "conceptos_parciales": [], "conceptos_criticos_faltantes": ["Alternativas comparadas"]}', 'chat.completions', 'rubrica-docente-v1', 'deepseek-chat', 'simuta-rubrica-v1', '{"conceptos": [{"cumple": false, "factor": 0.0, "evidencia": "No se mencionan alternativas comparadas.", "concepto_id": 1328, "retroalimentacion": "No se comparan opciones ni se analizan ventajas/desventajas de distintas alternativas."}, {"cumple": true, "factor": 1.0, "evidencia": "Propongo revisar proveedores, disminuir desperdicios en producción y producir de acuerdo con la demanda real.", "concepto_id": 1329, "retroalimentacion": "La decisión es concreta y menciona acciones específicas."}, {"cumple": false, "factor": 0.0, "evidencia": "No se mencionan riesgos ni controles.", "concepto_id": 1330, "retroalimentacion": "No se identifican riesgos ni se proponen medidas de control o seguimiento."}, {"cumple": true, "factor": 1.0, "evidencia": "Esta decisión ayuda porque el problema principal está en los costos altos y en el inventario lento.", "concepto_id": 1331, "retroalimentacion": "La justificación explica el beneficio esperado y la razón de la decisión."}], "finalizar": false, "siguiente_situacion": "La empresa implementa las mejoras en compras y producción, pero sin un plan de riesgos, podrían surgir problemas de calidad o desabastecimiento.", "retroalimentacion_general": "La decisión es concreta y está justificada, pero falta comparar alternativas y gestionar riesgos. Se recomienda incluir un análisis de opciones y medidas de control."}', 0, 0, '{}', '{}', '{}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (53, true, '2026-06-16 16:13:52.880642-05', '2026-06-16 16:13:52.880674-05', 3, 'La empresa implementa las mejoras en compras y producción, pero sin un plan de riesgos, podrían surgir problemas de calidad o desabastecimiento.', 'Primero revisaría los costos de producción para saber en qué se está gastando más. Luego compararía dos alternativas: cambiar o negociar con proveedores y mejorar el proceso de producción para reducir desperdicios. Escogería aplicar las dos poco a poco, empezando por negociar materia prima y controlar mejor el inventario. También se debe producir según las ventas reales para evitar que el inventario siga lento.', 'Este plan es viable porque no necesita una inversión muy alta y puede ayudar a bajar el costo unitario. El riesgo es que al cambiar proveedores baje la calidad o falte materia prima, por eso se debe probar primero con una compra pequeña. Para controlar el avance revisaría cada mes el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad. Si los indicadores no mejoran, se ajustaría el plan.', 'La decisión es coherente y bien justificada. Incluye un plan de acción con pasos concretos, indicadores de seguimiento y mecanismos de corrección. Se reconoce el riesgo de cambio de proveedores y se sugiere una prueba piloto.', '{"riesgo": -10.8, "impacto": 12.0, "claridad": 12.0, "viabilidad": 12.0, "calidad_analisis": 12.0}', '{"riesgo": 46.87, "impacto": 53.48, "claridad": 53.48, "viabilidad": 53.48, "calidad_analisis": 53.48}', '{"riesgo": 36.06999999999999, "impacto": 65.47999999999999, "claridad": 65.47999999999999, "viabilidad": 65.47999999999999, "calidad_analisis": 65.47999999999999}', 100.00, '[]', 41, NULL, 0.00, 100.00, 'La empresa inicia la negociación con proveedores y ajusta la producción a las ventas reales. En el primer mes, el costo unitario se reduce ligeramente, pero la rotación de inventario mejora. Se requiere monitorear la calidad de los nuevos insumos.', true, 'VALIDO', '{"tipo": "openai_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": true, "nombre": "Cierre justificable", "impacto": {"impacto": 8.0, "claridad": 10.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 1335, "descripcion": "Cierre justificable aplicado a Contabilidad de Costos.", "evidencia_ia": "Este plan es viable porque no necesita una inversión muy alta y puede ayudar a bajar el costo unitario.", "puntos_maximos": 20.0, "puntos_obtenidos": 20.0, "retroalimentacion": "El estudiante justifica su decisión con argumentos de viabilidad y beneficio esperado.", "factor_coincidencia": 1.0, "palabras_detectadas": ["porque"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Control y correccion", "impacto": {"riesgo": -10.0, "viabilidad": 8.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 1334, "descripcion": "Control y correccion aplicado a Contabilidad de Costos.", "evidencia_ia": "Para controlar el avance revisaría cada mes el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad. Si los indicadores no mejoran, se ajustaría el plan.", "puntos_maximos": 25.0, "puntos_obtenidos": 25.0, "retroalimentacion": "Propone seguimiento mensual y ajustes correctivos, evidenciando control y corrección.", "factor_coincidencia": 1.0, "palabras_detectadas": ["ajustar", "control", "mejora"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Indicadores de seguimiento", "impacto": {"riesgo": -8.0, "calidad_analisis": 10.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 1333, "descripcion": "Indicadores de seguimiento aplicado a Contabilidad de Costos.", "evidencia_ia": "revisaría cada mes el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad.", "puntos_maximos": 25.0, "puntos_obtenidos": 25.0, "retroalimentacion": "Define indicadores concretos de seguimiento (costo unitario, margen, rotación, punto de equilibrio, utilidad).", "factor_coincidencia": 1.0, "palabras_detectadas": ["control", "indicador", "kpi"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Plan de accion", "impacto": {"impacto": 8.0, "viabilidad": 15.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 1332, "descripcion": "Plan de accion aplicado a Contabilidad de Costos.", "evidencia_ia": "aplicar las dos poco a poco, empezando por negociar materia prima y controlar mejor el inventario. También se debe producir según las ventas reales.", "puntos_maximos": 30.0, "puntos_obtenidos": 30.0, "retroalimentacion": "Propone un plan de acción con pasos secuenciales: negociar materia prima, controlar inventario, producir según ventas.", "factor_coincidencia": 1.0, "palabras_detectadas": ["plan"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": null, "puntaje_sin_tope": 100, "puntaje_conceptos": 100.0, "conceptos_cumplidos": ["Cierre justificable", "Control y correccion", "Indicadores de seguimiento", "Plan de accion"], "conceptos_faltantes": [], "conceptos_parciales": [], "conceptos_criticos_faltantes": []}', 'chat.completions', 'rubrica-docente-v1', 'deepseek-chat', 'simuta-rubrica-v1', '{"conceptos": [{"cumple": true, "factor": 1.0, "evidencia": "Este plan es viable porque no necesita una inversión muy alta y puede ayudar a bajar el costo unitario.", "concepto_id": 1335, "retroalimentacion": "El estudiante justifica su decisión con argumentos de viabilidad y beneficio esperado."}, {"cumple": true, "factor": 1.0, "evidencia": "Para controlar el avance revisaría cada mes el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad. Si los indicadores no mejoran, se ajustaría el plan.", "concepto_id": 1334, "retroalimentacion": "Propone seguimiento mensual y ajustes correctivos, evidenciando control y corrección."}, {"cumple": true, "factor": 1.0, "evidencia": "revisaría cada mes el costo unitario, margen bruto, rotación de inventario, punto de equilibrio y utilidad.", "concepto_id": 1333, "retroalimentacion": "Define indicadores concretos de seguimiento (costo unitario, margen, rotación, punto de equilibrio, utilidad)."}, {"cumple": true, "factor": 1.0, "evidencia": "aplicar las dos poco a poco, empezando por negociar materia prima y controlar mejor el inventario. También se debe producir según las ventas reales.", "concepto_id": 1332, "retroalimentacion": "Propone un plan de acción con pasos secuenciales: negociar materia prima, controlar inventario, producir según ventas."}], "finalizar": true, "siguiente_situacion": "La empresa inicia la negociación con proveedores y ajusta la producción a las ventas reales. En el primer mes, el costo unitario se reduce ligeramente, pero la rotación de inventario mejora. Se requiere monitorear la calidad de los nuevos insumos.", "retroalimentacion_general": "La decisión es coherente y bien justificada. Incluye un plan de acción con pasos concretos, indicadores de seguimiento y mecanismos de corrección. Se reconoce el riesgo de cambio de proveedores y se sugiere una prueba piloto."}', 0, 0, '{}', '{}', '{}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (137, true, '2026-06-17 18:20:59.364801-05', '2026-06-17 18:20:59.364824-05', 1, 'TechAndes te pide un informe en tres etapas. Primero: elige como evaluarias a los finalistas. El puesto requiere Django, DRF, ORM, testing y comunicacion con el equipo. Debes definir criterios medibles y una prueba tecnica real para diferenciar a candidatos parecidos. Justifica con datos del puesto.', 'Aplicar prueba integral: code review, mini feature Django, ORM, testing y entrevista por competencias', 'Selecciono una prueba integral porque el puesto requiere validar competencias técnicas reales en Django, DRF/API, ORM y testing. Esta evaluación permite comparar a los candidatos con criterios medibles, revisar su calidad de código, su capacidad para resolver un mini feature funcional y su forma de explicar decisiones técnicas. Además, ayuda a reducir el riesgo de contratación y elegir al candidato con mejor equilibrio entre conocimiento técnico, comunicación y encaje con el equipo.', 'La decision es solida y cubre la mayoria de los conceptos. Se sugiere reforzar la justificacion con datos especificos del puesto (ej. requisitos tecnicos detallados) para cumplir plenamente el concepto de justificacion. Impacto real de la jugada: Indicadores propios afectados: Ajuste al perfil del puesto +15.0 (mejora); Riesgo de rotacion -8.0 (mejora); Competencia tecnica (Django) +18.0 (mejora); Tiempo a productividad -2.0 (mejora).', '{"ajuste_perfil": 15, "riesgo_rotacion": -8, "competencia_tecnica": 18, "tiempo_productividad": -2}', '{"clima_equipo": 50.0, "ajuste_perfil": 50.0, "riesgo_rotacion": 55.0, "costo_contratacion": 1350.0, "competencia_tecnica": 50.0, "tiempo_productividad": 10.0}', '{"__eventos__": [], "clima_equipo": 50.0, "ajuste_perfil": 65.0, "riesgo_rotacion": 47.0, "costo_contratacion": 1350.0, "competencia_tecnica": 68.0, "tiempo_productividad": 8.0}', 77.50, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actual": 65.0}, {"limite": 70.0, "operador": ">=", "indicador": "competencia_tecnica", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": 12.0, "valor_actual": 68.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 47.0}, {"limite": 6.0, "operador": "<=", "indicador": "tiempo_productividad", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": 6.0, "valor_actual": 8.0}]', 102, NULL, 15.00, 92.50, 'El equipo de TechAndes revisa tu propuesta de evaluacion integral y te pide que disenies la prueba tecnica concreta para la siguiente ronda.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": true, "nombre": "Definicion del perfil y criterios medibles", "impacto": {"ajuste_perfil": 15.0, "riesgo_rotacion": -5.0}, "parcial": false, "cumple_ia": true, "es_critico": true, "concepto_id": 2372, "descripcion": "Definicion del perfil y criterios medibles aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "prueba integral con criterios medibles: code review, mini feature Django, ORM, testing y entrevista por competencias", "puntos_maximos": 35.0, "puntos_obtenidos": 35.0, "retroalimentacion": "Define claramente criterios medibles (code review, mini feature, testing) alineados con el perfil del puesto.", "factor_coincidencia": 1.0, "palabras_detectadas": ["criterios", "competencias", "medible"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Identificar diferenciadores reales", "impacto": {"competencia_tecnica": 6.0}, "parcial": false, "cumple_ia": true, "es_critico": false, "concepto_id": 2374, "descripcion": "Identificar diferenciadores reales aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "menciona testing, DRF/API, Django y comunicacion como elementos diferenciadores", "puntos_maximos": 20.0, "puntos_obtenidos": 20.0, "retroalimentacion": "Identifica diferenciadores reales como testing, DRF y comunicacion, claves para el puesto.", "factor_coincidencia": 1.0, "palabras_detectadas": ["testing", "drf", "comunicacion", "django"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Justificacion con datos del puesto", "impacto": {"ajuste_perfil": 1.5}, "parcial": true, "cumple_ia": true, "es_critico": false, "concepto_id": 2375, "descripcion": "Justificacion con datos del puesto aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "justifica que el puesto requiere validar competencias técnicas reales", "puntos_maximos": 15.0, "puntos_obtenidos": 7.5, "retroalimentacion": "Menciona la necesidad del puesto pero no cita datos concretos (ej. requisitos del puesto, datos de negocio).", "factor_coincidencia": 0.5, "palabras_detectadas": ["porque", "dato"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": true, "nombre": "Metodo de evaluacion objetivo", "impacto": {"ajus