INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (101, true, '2026-06-17 13:43:08.583759-05', '2026-06-17 13:43:08.583806-05', 1, 'TechAndes te pide un informe en tres etapas. Primero: como Analista de Talento Humano, define el perfil real del puesto, los criterios medibles (tecnicos y de equipo) y el metodo de evaluacion (prueba tecnica en Django, entrevista por competencias) que usarias para diferenciar a 3 candidatos casi iguales. Justifica con datos del puesto.', 'Elegir al mas barato sin prueba tecnica para ahorrar tiempo', 'Riesgoso: decides a ciegas, sube el riesgo de rotacion y mala contratacion.', 'La decision no cumple con ningun concepto: no define perfil, no identifica diferenciadores, no justifica con datos y no propone metodo de evaluacion. Se recomienda replantear la estrategia.', '{"ajuste_perfil": -10, "riesgo_rotacion": 15, "competencia_tecnica": -8}', '{"clima_equipo": 50.0, "ajuste_perfil": 50.0, "riesgo_rotacion": 55.0, "costo_contratacion": 1350.0, "competencia_tecnica": 50.0, "tiempo_productividad": 10.0}', '{"__eventos__": [], "clima_equipo": 50.0, "ajuste_perfil": 40.0, "riesgo_rotacion": 70.0, "costo_contratacion": 1350.0, "competencia_tecnica": 42.0, "tiempo_productividad": 10.0}', 0.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actual": 40.0}, {"limite": 70.0, "operador": ">=", "indicador": "competencia_tecnica", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": 12.0, "valor_actual": 42.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 70.0}]', 70, NULL, 15.00, 0.00, 'El informe es rechazado por falta de criterios tecnicos. TechAndes solicita un nuevo analisis con metodos objetivos.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Definicion del perfil y criterios medibles", "impacto": {"ajuste_perfil": -8}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1744, "descripcion": "Definicion del perfil y criterios medibles en TechAndes.", "evidencia_ia": "Elegir al mas barato sin prueba tecnica", "puntos_maximos": 35.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se define perfil ni criterios medibles; la decision ignora la rubrica.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["perfil", "criterios", "requisitos", "competencias", "medible", "rubrica", "descripcion del puesto", "ponderado"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Identificar diferenciadores reales", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1746, "descripcion": "Identificar diferenciadores reales en TechAndes.", "evidencia_ia": "Elegir al mas barato sin prueba tecnica", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se identifican diferenciadores; no hay evaluacion tecnica.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["diferencia", "testing", "escalabilidad", "drf", "consultas", "documentacion", "comunicacion", "django"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Justificacion con datos del puesto", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1747, "descripcion": "Justificacion con datos del puesto en TechAndes.", "evidencia_ia": "Riesgoso: decides a ciegas, sube el riesgo de rotacion y mala contratacion", "puntos_maximos": 15.0, "puntos_obtenidos": 0.0, "retroalimentacion": "La justificacion menciona riesgos pero no datos del puesto.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["porque", "dato", "requisito", "negocio", "necesidad"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Metodo de evaluacion objetivo", "impacto": {"competencia_tecnica": -6}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1745, "descripcion": "Metodo de evaluacion objetivo en TechAndes.", "evidencia_ia": "Elegir al mas barato sin prueba tecnica", "puntos_maximos": 30.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se propone metodo objetivo de evaluacion.", "factor_coincidencia": 0.0, "palabras_detectadas": ["prueba tecnica"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor": "deepseek", "tope_critico": 70.0, "costo_recursos": {"tiempo": 2.0, "presupuesto": 10.0, "capacidad_equipo": 10.0}, "alertas_recursos": [], "puntaje_sin_tope": 0, "puntaje_conceptos": 0, "conceptos_cumplidos": [], "conceptos_faltantes": ["Definicion del perfil y criterios medibles", "Identificar diferenciadores reales", "Justificacion con datos del puesto", "Metodo de evaluacion objetivo"], "conceptos_parciales": [], "penalizacion_recursos": 0, "accion_sugerida_detectada": "Elegir al mas barato sin prueba tecnica para ahorrar tiempo", "conceptos_criticos_faltantes": ["Definicion del perfil y crit