cnica", "descripcion": "La competencia tecnica en Django debe ser >= 70%.", "penalizacion": 12.0, "valor_actual": 44.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 43.0}, {"limite": 6.0, "operador": "<=", "indicador": "tiempo_productividad", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": 6.0, "valor_actual": 7.0}]', 85, NULL, 15.00, 0.00, 'El informe inicial es rechazado por no cumplir con los requisitos. TechAndes solicita una nueva propuesta centrada en la definición del perfil y criterios de selección.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Definicion del perfil y criterios medibles", "impacto": {"ajuste_perfil": -8}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 1744, "descripcion": "Definicion del perfil y criterios medibles en TechAndes.", "evidencia_ia": "No se menciona perfil ni criterios medibles.", "puntos_maximos": 35.0, "puntos_obtenidos": 0.0, "retroalimentacion": "La decisión no aborda la definición del perfil ni los criterios medibles requeridos.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["perfil", "criterios", "requisitos", "competencias", "medible", "rubrica", "descripcion del puesto", "ponderado"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Identificar diferenciadores reales", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 1746, "descripcion": "Identificar diferenciadores reales en TechAndes.", "evidencia_ia": "No se identifican diferenciadores.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se men