INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (113, true, '2026-06-17 16:29:09.281352-05', '2026-06-17 16:29:09.281384-05', 1, 'TechAndes te pide un informe en tres etapas. Primero: como Analista de Talento Humano, define el perfil real del puesto, los criterios medibles (tecnicos y de equipo) y el metodo de evaluacion (prueba tecnica en Django, entrevista por competencias) que usarias para diferenciar a 3 candidatos casi iguales. Justifica con datos del puesto.', 'Usar entrevista por competencias con criterios y rubrica ponderada', 'si eso debe ser mejro para no escojer ocmo sea', 'La decisión es vaga y carece de sustento. No se define el perfil del puesto, no se identifican diferenciadores, no se justifica con datos y el método de evaluación no está detallado. Se recomienda revisar los conceptos clave y proporcionar evidencia concreta.', '{"clima_equipo": 8, "ajuste_perfil": 15, "riesgo_rotacion": -10, "competencia_tecnica": 6.0}', '{"clima_equipo": 50.0, "ajuste_perfil": 50.0, "riesgo_rotacion": 55.0, "costo_contratacion": 1350.0, "competencia_tecnica": 50.0, "tiempo_productividad": 10.0}', '{"__eventos__": [], "clima_equipo": 58.0, "ajuste_perfil": 65.0, "riesgo_rotacion": 45.0, "costo_contratacion": 1350.0, "competencia_tecnica": 56.0, "tiempo_productividad": 10.0}', 0.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actu