INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (118, true, '2026-06-17 16:38:33.799886-05', '2026-06-17 16:38:33.799937-05', 2, 'TechAndes rechaza el informe por falta de fundamentos y solicita una nueva propuesta con perfil detallado y metodo objetivo.', 'Contratar a Marta Sanchez', 'Muy fuerte en BD/ORM, pero requiere acompanamiento en comunicacion.', 'La decision carece de fundamentos objetivos y no aborda criterios clave como costo, riesgo o comparacion entre candidatos. Se requiere una justificacion mas completa basada en datos y perfil del puesto. Impacto real de la jugada: Indicadores propios afectados: Ajuste al perfil del puesto +8.0 (mejora); Competencia tecnica (Django) +14.0 (mejora); Tiempo a productividad -1.0 (mejora); Encaje con el equipo -8.0 (empeora); Riesgo de rotacion +4.0 (empeora); Costo de contratacion +50.0 (empeora).', '{"clima_equipo": -8, "ajuste_perfil": 8, "riesgo_rotacion": 4, "costo_contratacion": 50, "competencia_tecnica": 14, "tiempo_productividad": -1}', '{"__eventos__": [], "clima_equipo": 50.0, "ajuste_perfil": 48.0, "riesgo_rotacion": 55.0, "costo_contratacion": 1350.0, "competencia_tecnica": 56.0, "tiempo_productividad": 11.0}', '{"__eventos__": ["db:43"], "clima_equipo": 42.0, "ajuste_perfil": 56.0, "riesgo_rotacion": 71.0, "costo_contratacion": 1520.0, "competencia_tecnica": 70.0, "tiempo_productividad": 10.0}', 0.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El