41, "descripcion": "Evaluacion tecnica (Django) aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Menciona ''BD/ORM'' que es parte de Django, pero no incluye otros terminos como testing, DRF, code review, etc.", "puntos_maximos": 30.0, "puntos_obtenidos": 15.0, "retroalimentacion": "Se reconoce la fortaleza en BD/ORM, pero no se mencionan otros aspectos tecnicos como testing, DRF o code review. La evaluacion tecnica es parcial.", "factor_coincidencia": 0.5, "palabras_detectadas": ["orm"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": ["django"]}, {"cumple": false, "nombre": "Gestion de costo y riesgo de rotacion", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2342, "descripcion": "Gestion de costo y riesgo de rotacion aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No menciona ''riesgo'' ni rotacion, salario, costo, presupuesto o retencion.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se aborda el costo de contratacion ni el riesgo de rotacion. No hay evidencia de gestion de estos aspectos.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["rotacion", "salario", "costo", "presupuesto", "retencion"], "obligatorias_faltantes": ["riesgo"]}, {"cumple": false, "nombre": "Justificacion objetiva sin sesgo", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2343, "descripcion": "Justificacion objetiva sin sesgo aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No menciona ''compar'' ni evidencia, objetivo, criterio, resultado, puntaje o datos.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "La justificacion no compara candidatos ni presenta datos objetivos. Falta evidencia que sustente la decision sin sesgo.