": 0.0, "evidencia": "No menciona ''compar'' ni evidencia, objetivo, criterio, resultado, puntaje o datos.", "concepto_id": 2343, "retroalimentacion": "La justificacion no compara candidatos ni presenta datos objetivos. Falta evidencia que sustente la decision sin sesgo."}], "finalizar": false, "siguiente_situacion": "TechAndes solicita una nueva propuesta que incluya comparacion objetiva de los candidatos, analisis de costo y riesgo, y evidencia tecnica detallada.", "retroalimentacion_general": "La decision carece de fundamentos objetivos y no aborda criterios clave como costo, riesgo o comparacion entre candidatos. Se requiere una justificacion mas completa basada en datos y perfil del puesto."}', 1884, 535, '{}', '{"tiempo": 12.0, "presupuesto": 100.0, "capacidad_equipo": 40.0}', '{"tiempo": 12.0, "presupuesto": 100.0, "capacidad_equipo": 40.0}');
INSERT INTO public.simulador_pasosimulacion (id, activo, fecha_creacion, fecha_modificacion, numero, situacion_presentada, decision_estudiante, justificacion_estudiante, evaluacion_ia, impacto_calculado, estado_antes, estado_despues, puntaje_paso, alertas_restricciones, intento_id, usuario_creacion_id, penalizacion_aplicada, puntaje_ia_sugerido, siguiente_situacion, es_valido, tipo_paso, evaluacion_detalle, api_ia, esquema_ia_version, modelo_ia, prompt_version, respuesta_ia_estructurada, tokens_entrada, tokens_salida, costo_recursos, recursos_antes, recursos_despues) VALUES (119, true, '2026-06-17 16:38:45.788353-05', '2026-06-17 16:38:45.788387-05', 3, 'TechAndes solicita una nueva propuesta que incluya comparacion objetiva de los candidatos, analisis de costo y riesgo, y evidencia tecnica detallada. ⚡ Uno de los candidatos recibe una contraoferta externa; ahora la decision debe considerar retencion y costo real.', 'Hacer una induccion de un dia y asignar tareas sin seguimiento', 'Arranca rapido, pero deja brechas de acompanamiento y medicion.', 'La decisión es incompleta: falta plan de onboarding estructurado, retención ante contraoferta y seguimiento del desempeño. Se recomienda detallar acciones concretas para cada concepto crítico. Impacto real de la jugada: Indicadores propios afectados: Ajuste al perfil del puesto +4.0 (mejora); Tiempo a productividad +2.0 (empeora); Riesgo de rotacion +8.0 (empeora); Encaje con el equipo -5.0 (empeora).', '{"clima_equipo": -5, "ajuste_perfil": 4.0, "riesgo_rotacion": 8, "tiempo_productividad": 2}', '{"__eventos__": ["db:43"], "clima_equipo": 42.0, "ajuste_perfil": 56.0, "riesgo_rotacion": 71.0, "costo_contratacion": 1520.0, "competencia_tecnica": 70.0, "tiempo_productividad": 10.0}', '{"__eventos__": ["db:43"], "clima_equipo": 37.0, "ajuste_perfil": 60.0, "riesgo_rotacion": 79.0, "costo_contratacion": 1520.0, "competencia_tecnica": 70.0, "tiempo_productividad": 12.0}', 0.00, '[{"limite": 70.0, "operador": ">=", "indicador": "ajuste_perfil", "descripcion": "El candidato debe ajustarse al perfil (>= 70%).", "penalizacion": 12.0, "valor_actual": 60.0}, {"limite": 40.0, "operador": "<=", "indicador": "riesgo_rotacion", "descripcion": "El riesgo de rotacion debe quedar <= 40%.", "penalizacion": 10.0, "valor_actual": 79.0}, {"limite": 6.0, "operador": "<=", "indicador": "tiempo_productividad", "descripcion": "El tiempo a productividad debe ser <= 6 semanas.", "penalizacion": 6.0, "valor_actual": 12.0}]', 89, NULL, 15.00, 15.00, 'El nuevo desarrollador inicia con una inducción mínima, pero al no tener acompañamiento ni metas claras, su productividad es baja y surgen dudas sobre su adaptación. Además, la contraoferta externa sigue latente, aumentando el riesgo de rotación.', true, 'VALIDO', '{"tipo": "ia_rubrica_docente", "modelo": "deepseek-chat", "calculo": "La nota e impactos se calculan con pesos, conceptos e indicadores configurados por el docente.", "conceptos": [{"cumple": false, "nombre": "Mejora del proceso de seleccion", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2347, "descripcion": "Mejora del proceso de seleccion aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No se menciona mejora, lección, documentación, proceso o correctiva.", "puntos_maximos": 20.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se evidencia mejora del proceso de selección; la decisión no incluye acciones correctivas ni documentación.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["mejora", "leccion", "documentacion", "proceso", "correctiva"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Plan de onboarding", "impacto": {"ajuste_perfil": 4.0, "tiempo_productividad": -1.5}, "parcial": true, "cumple_ia": true, "es_critico": true, "concepto_id": 2344, "descripcion": "Plan de onboarding aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "Inducción de un día, pero sin acompañamiento ni plan estructurado.", "puntos_maximos": 30.0, "puntos_obtenidos": 15.0, "retroalimentacion": "Se menciona inducción, pero falta un plan de onboarding completo con mentoría y objetivos claros.", "factor_coincidencia": 0.5, "palabras_detectadas": ["induccion", "acompanamiento"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Retencion y plan de carrera", "impacto": {"riesgo_rotacion": 5}, "parcial": false, "cumple_ia": false, "es_critico": true, "concepto_id": 2345, "descripcion": "Retencion y plan de carrera aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No se aborda retención, plan de carrera, feedback, salario, clima o reconocimiento.", "puntos_maximos": 25.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No se considera retención ni plan de carrera; la contraoferta externa no es gestionada.", "factor_coincidencia": 0.0, "palabras_detectadas": [], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": ["retencion", "plan de carrera", "crecimiento", "feedback", "salario", "clima", "reconocimiento"], "obligatorias_faltantes": []}, {"cumple": false, "nombre": "Seguimiento del desempeno", "impacto": {}, "parcial": false, "cumple_ia": false, "es_critico": false, "concepto_id": 2346, "descripcion": "Seguimiento del desempeno aplicado a Gestion y Administracion del Talento Humano.", "evidencia_ia": "No se menciona seguimiento, KPI, objetivos, evaluación, periodo de prueba o metas.", "puntos_maximos": 25.0, "puntos_obtenidos": 0.0, "retroalimentacion": "No hay seguimiento del desempeño; asignar tareas sin seguimiento no permite evaluar resultados.", "factor_coincidencia": 0.0, "palabras_detectadas": ["seguimiento"], "sinonimos_detectados": [], "prohibidas_detectadas": [], "alternativas_faltantes": [], "obligatorias_faltantes": []}], "proveedor":