INSERT INTO public.simulador_plantillaronda (id, activo, fecha_creacion, fecha_modificacion, numero, titulo, proposito, consigna_base, etiqueta_decision, etiqueta_justificacion, usuario_creacion_id, plantilla_id, opciones_decision) VALUES (1, true, '2026-06-14 15:47:13.001832-05', '2026-06-14 15:47:13.001835-05', 1, 'Analisis inicial', 'Identificar problema, causas, datos e indicadores.', 'Describe el problema principal de {materia}, sus causas probables y los indicadores que usarias para medirlo.', 'Analisis inicial', 'Justificacion', NULL, 1, '[{"texto": "Analizar causas con datos de {materia} antes de intervenir", "impacto": {"riesgo": -4, "claridad": 5, "calidad_analisis": 10}, "descripcion": "Levantar datos, linea base e indicadores para identificar el problema principal."}, {"texto": "Priorizar el indicador critico con mayor riesgo", "impacto": {"riesgo": -6, "calidad_analisis": 8}, "descripcion": "Enfocar el diagnostico en el indicador que mas amenaza el resultado del caso."}, {"texto": "Solicitar datos complementarios y definir linea base", "impacto": {"riesgo": -3, "claridad": 6, "viabilidad": 5}, "descripcion": "Validar informacion faltante antes de proponer una accion de fondo."}]');
INSERT INTO public.simulador_plantillaronda (id, activo, fecha_creacion, fecha_modificacion, numero, titulo, proposito, consigna_base, etiqueta_decision, etiqueta_justificacion, usuario_creacion_id, plantilla_id, opciones_decision) VALUES (2, true, '2026-06-14 15:47:13.003171-05', '2026-06-14 15:47:13.003176-05', 2, 'Alternativas y decision', 'Comparar alternativas y elegir una decision concreta.', 'Compara al menos dos alternativas, selecciona la mas viable y justifica la decision con criterios de {materia}.', 'Alternativas y decision', 'Justificacion', NULL, 1, '[{"texto": "Comparar alternativas y seleccionar la opcion mas viable", "impacto": {"riesgo": -5, "viabilidad": 8, "calidad_analisis": 8}, "descripcion": "Contrastar ventajas, desventajas, costo, impacto y riesgo antes de decidir."}, {"texto": "Implementar una accion de bajo riesgo con control inmediato", "impacto": {"riesgo": -6, "impacto": 6, "viabilidad": 10}, "descripcion": "Elegir una decision ejecutable en corto plazo y medir sus efectos."}, {"texto": "Escalar una decision de alto impacto con plan de mitigacion", "impacto": {"riesgo": 4, "impacto": 10, "calidad_analisis": 5}, "descripcion": "Tomar una accion fuerte si se justifica con controles y responsables."}]');
INSERT INTO public.simulador_plantillaronda (id, activo, fecha_creacion, fecha_modificacion, numero, titulo, proposito, consigna_base, etiqueta_decision, etiqueta_justificacion, usuario_creacion_id, plantilla_id, opciones_decision) VALUES (3, true, '2026-06-14 15:47:13.003563-05', '2026-06-14 15:47:13.003567-05', 3, 'Implementacion y control', 'Definir plan, responsables, control y correccion.', 'Propone un plan de implementacion con acciones, responsables, indicadores de seguimiento y medidas correctivas.', 'Implementacion y control', 'Justificacion', NULL, 1, '[{"texto": "Ejecutar plan con responsables, fechas e indicadores", "impacto": {"impacto": 6, "claridad": 5, "viabilidad": 10}, "descripcion": "Convertir la decision en actividades verificables y medibles."}, {"texto": "Ajustar la decision segun resultados de seguimiento", "impacto": {"riesgo": -6, "viabilidad": 5, "calidad_analisis": 6}, "descripcion": "Revisar indicadores y corregir la accion si no produce el resultado esperado."}, {"texto": "Cerrar la simulacion con evidencia y acciones correctivas", "impacto": {"riesgo": -4, "impacto": 5, "claridad": 8}, "descripcion": "Presentar resultados, aprendizajes y controles para sostener la mejora."}]');
